{
    "settings" : {
        "number_of_shards" :   1,
        "number_of_replicas" : 0,
        "index" : {
            "sort.field" : "date", 
            "sort.order" : "desc" 
        }
    },
    "mappings": {
        "tweet": {
            "properties": {
                "field1": {
                    "type": "keyword"
                },
                "date": {
                    "type": "date",
                    "format": "yyyy-MM-dd"
                }
            }
        }
    }
}
'
curl -XPOST 'localhost:9200/_bulk?pretty' -H 'Content-Type: application/json' -d'
{ "index" : { "_index" : "twitter", "_type" : "tweet", "_id" : "1" } }
{ "field1" : "value1", "date" : "2017-08-28" }
{ "index" : { "_index" : "twitter", "_type" : "tweet", "_id" : "2" } }
